		var sl = Math.sin(L);
		var x = Math.cos(L);
		var y = COSEPS * sl;
		var Z = SINEPS * sl;
		var rho = Math.sqrt(1 - Z * Z);
		var dec = (360 / p2) * Math.atan(Z / rho);
		var ra = (48 / p2) * Math.atan(y / (x + rho));
