	/**
	 * 大写数字
	 */
	this.dx = function(number) {
		var string = '';
		number = '' + number;
		for (var i = 0; i < number.length; i++) {
			string += this.dxs[number[i]];
		}
		return string;
	}
	/**
	 * 从天干地支数组查出所有刑冲合害关系
	 * @param array tg 天干数组
	 * @param array dz 地支数组
	 * @return array [[], []]
	 */
	this.GetGX = function(tg, dz) {
		var list = [
			[],
			[]
		]; //两个列表:0位是天干关系列表,1位是地支关系列表
		var hook = [];
		var excludes = {
			4: 3, //相刑要把三刑(3)排除
			8: 7, //半合要把三合(7)排除
			9: 7, //拱合要把三合(7)排除
			11: 10 //拱会要把三会(10)排除
		};
		for (var i in this.GX) { //[0针对天干1针对地支, 关系类型, [发起者...], 形成者, 文字描述]
			var gx = this.GX[i];
			var to = (gx[0] == 0) ? tg : dz; //要匹配的类型
			var fd = array_intersect(to, gx[2]); //求交集,返回的键名与to是一致的
			if (empty(array_diff(gx[2], fd))) { //说明存在此关系
				var c1 = count(fd);
				var c2 = count(gx[2]);
				var fds = []; //最终关联的
				if (c1 < c2) { //比如亥亥自刑,在只有一个亥的时候也会来这里
				}
				if (c1 == c2) { //有且只有一个此类关系
					array_push(fds, fd);
				}
				if (c1 > c2) { //存在多个此类关系,先算出所有可能的组合,再匹配判断以精确指定是哪一个位置
					var set = pc_array_power_set(array_keys(fd));
					for (var ii in set) {
						var keys = set[ii];
						if (count(keys) != c2) {
							continue;
						}
						var fd = [];
						for (var iii in keys) {
							fd[keys[iii]] = to[keys[iii]];
						}
						if (empty(array_diff(gx[2], fd))) {
							array_push(fds, fd);
						}
					}
				}
				b1: for (var j in fds) { //组合成期望的返回
					b2: for (var expect in excludes) {
						if (gx[1] == expect) {
							b3: for (var jj in list[gx[0]]) { //其实仅针对地支有这种情况
								var [fd2, fd2k, gx2] = list[gx[0]][jj];
								if (gx2[1] == excludes[expect]) {
									if (array_intersect(gx[2], gx2[2])) {
										break b1;
									}
								}
							}
							break;
						}
					}
					var e = [fds[j], array_keys(fds[j]), gx];
					array_push(list[gx[0]], e);
					if (empty(hook[i])) {
						hook[i] = e[1];
					} else {
						hook[i] = array_values(array_unique(array_merge(hook[i], e[1]))).sort();
					}
				}
			}
		}
		//return list;
		return hook;
	}
